compliant:
// Path validation and sanitization
[HttpGet("api/{path}")]
public async Task<string> GetApiData(string path)
{
    // Validate path doesn't contain traversal sequences
    if (path.Contains("..") || path.Contains("/") || path.Contains("\"))
    {
        throw new ArgumentException("Invalid path");
    }

    var allowedPaths = new[] { "users", "products", "orders" };
    if (!allowedPaths.Contains(path))
    {
        throw new ArgumentException("Path not allowed");
    }

    var baseUrl = "https://internal-api.com/";
    var fullUrl = $"{baseUrl}{path}";
    return await new HttpClient().GetStringAsync(fullUrl);
}

// Using Path.GetFileName to prevent traversal
public async Task<string> FetchFile(string fileName)
{
    // Extract only the filename, removing any path components
    var safeName = Path.GetFileName(fileName);

    // Additional validation
    if (string.IsNullOrEmpty(safeName) || safeName.Contains('.'))
    {
        throw new ArgumentException("Invalid filename");
    }

    var apiEndpoint = $"https://fileserver.com/files/{safeName}";
    return await new HttpClient().GetStringAsync(apiEndpoint);
}

// Allowlist approach for documents
public async Task<IActionResult> DownloadDocument(string documentId)
{
    var allowedDocuments = new Dictionary<string, string>
    {
        ["report1"] = "reports/monthly-summary.pdf",
        ["guide1"] = "guides/user-manual.pdf"
    };

    if (!allowedDocuments.TryGetValue(documentId, out var documentPath))
    {
        return NotFound();
    }

    var url = $"https://docs.internal/{documentPath}";
    var response = await new HttpClient().GetAsync(url);
    return File(await response.Content.ReadAsStreamAsync(), "application/pdf");
}
